function solve(l_in, r_in, directions) {
    const L = BigInt(l_in);
    const R = BigInt(r_in);
    let count = 0;

    /**
     * Checks if a number x results in a non-decreasing sequence based on grid traversal.
     * @param {bigint} x - The number to check.
     * @returns {boolean} True if x is a good integer, false otherwise.
     */
    const isGood = (x) => {
        // 1. Formatting: 16-digit string with leading zeros
        const xStr = x.toString().padStart(16, '0');

        // 2. Grid Filling (4x4)
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));

        // Populate the grid row by row (i = 0 to 15)
        for (let i = 0; i < 16; i++) {
            // xStr[i] is guaranteed to be a character '0'-'9'
            const digit = parseInt(xStr[i]);
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = digit;
        }

        // 3. Traversal
        let r = 0;
        let c = 0;
        const sequence = [];

        // Record start cell (0, 0) value
        sequence.push(grid[0][0]);

        // Apply 6 directions to find 6 subsequent cells
        for (let i = 0; i < 6; i++) {
            const move = directions[i];

            if (move === 'D') {
                r += 1;
            } else { // move === 'R'
                c += 1;
            }

            // Assuming the path stays within 4x4 bounds as per problem constraints
            if (r >= 4 || c >= 4 || r < 0 || c < 0) {
                // Should not happen based on problem description
                // If it did, handling depends on precise specification for out-of-bounds movement
                break; 
            }

            // Record value at the new position (r, c)
            sequence.push(grid[r][c]);
        }

        // 4. Verification: Check for non-decreasing sequence (length 7)
        for (let i = 0; i < 6; i++) {
            if (sequence[i] > sequence[i+1]) {
                return false;
            }
        }
        return true;
    };

    // Main loop iteration
    let currentX = L;
    while (currentX <= R) {
        if (isGood(currentX)) {
            count++;
        }
        currentX++;
    }

    return count;
}

