// DP table: dp[index][tight_L][tight_R][V_prev]
// Index: 0 to 16 (17 states)
// tight_L, tight_R: 0 or 1 (2 states each)
// V_prev: 0 to 9 (digit value), 10 (initial state/no constraint yet) (11 states)
long long memo[17][2][2][11];
string S_limit;
vector<int> path_indices;
map<int, int> index_to_k; // Maps digit index i (0-15) to sequence index k (0-6) if i is in path_indices

// Recursive DP function
long long dp(int idx, bool tightL, bool tightR, int V_prev) {
    if (idx == 16) {
        return 1;
    }

    if (memo[idx][tightL][tightR][V_prev] != -1) {
        return memo[idx][tightL][tightR][V_prev];
    }

    long long ans = 0;
    int low = tightL ? (S_limit[idx] - '0') : 0;
    int high = tightR ? (S_limit[idx] - '0') : 9;

    // Check if the current index idx is constrained by the path
    bool is_constrained_now = index_to_k.count(idx);
    int k = is_constrained_now ? index_to_k[idx] : -1;

    for (int d = low; d <= high; ++d) {

        int next_V_prev = V_prev;
        bool constraint_ok = true;

        if (is_constrained_now) {
            // This digit d is d_I_k. It must be >= d_I_{k-1}.
            // d_I_{k-1} is stored in V_prev.
            if (d < V_prev) {
                constraint_ok = false;
            } else {
                // Update V_prev for the next constrained digit to d
                next_V_prev = d;
            }
        }

        if (constraint_ok) {
            bool newTightL = tightL && (d == low);
            bool newTightR = tightR && (d == high);

            ans += dp(idx + 1, newTightL, newTightR, next_V_prev);
        }
    }

    return memo[idx][tightL][tightR][V_prev] = ans;
}

// Helper function to count valid numbers <= N
long long count_valid(long long N, const string& directions) {
    if (N < 0) return 0;

