    index_to_k.clear();
    for (int k = 0; k < 7; ++k) {
        index_to_k[I_indices[k]] = k;
    }

    // 2. Prepare Limit String S_limit (16 digits, padded)
    S_limit = to_string(N);
    string padded_S = string(16 - S_limit.length(), '0') + S_limit;
    S_limit = padded_S;

    // 3. Initialize Memoization Table
    memset(memo, -1, sizeof(memo));

    // V_prev = 10 signifies no constraint yet (before I_0)
    return dp(0, true, true, 10);
}


