    const isGood = (x) => {
        // 1. Formatting: 16-digit string with leading zeros
        const xStr = x.toString().padStart(16, '0');

        // 2. Grid Filling (4x4)
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));

        // Populate the grid row by row (i = 0 to 15)
        for (let i = 0; i < 16; i++) {
            // xStr[i] is guaranteed to be a character '0'-'9'
            const digit = parseInt(xStr[i]);
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = digit;
        }

        // 3. Traversal
        let r = 0;
        let c = 0;
        const sequence = [];

        // Record start cell (0, 0) value
        sequence.push(grid[0][0]);

        // Apply 6 directions to find 6 subsequent cells
        for (let i = 0; i < 6; i++) {
